/**
 * Manual test: Verify baseUrl works for custom endpoints (like proxies)
 *
 * This test verifies that setting baseUrl to a custom endpoint correctly
 * routes ALL requests (auth, listen, manage) to that endpoint
 *
 * Run with: DEEPGRAM_API_KEY=your_key node dist/cjs/tests/manual/test-custom-baseurl.js
 */
const { DeepgramClient } = require("../../dist/cjs/index.js");
const http = require("http");
// Simple mock proxy server that logs what endpoints are being hit
function createMockProxyServer(port) {
    const requestLog = [];
    const server = http.createServer((req, res) => {
        const requestInfo = {
            method: req.method,
            url: req.url,
            path: new URL(req.url, `http://localhost:${port}`).pathname,
            headers: req.headers,
        };
        console.log(`  [Proxy] ${req.method} ${requestInfo.path}`);
        requestLog.push(requestInfo);
        // Return a minimal valid response for different endpoints
        res.writeHead(200, { "Content-Type": "application/json" });
        if (requestInfo.path === "/v1/auth/grant") {
            res.end(JSON.stringify({ token: "mock_token_12345" }));
        }
        else if (requestInfo.path === "/v1/projects") {
            res.end(JSON.stringify({ projects: [{ project_id: "test", name: "Test Project" }] }));
        }
        else if (requestInfo.path === "/v1/listen") {
            res.end(JSON.stringify({
                metadata: { request_id: "test" },
                results: {
                    channels: [{
                            alternatives: [{
                                    transcript: "This is a mock transcription."
                                }]
                        }]
                }
            }));
        }
        else {
            res.end(JSON.stringify({ success: true }));
        }
    });
    return new Promise((resolve) => {
        server.listen(port, () => {
            console.log(`Mock proxy server listening on http://localhost:${port}\n`);
            resolve({ server, requestLog });
        });
    });
}
async function testCustomBaseUrl() {
    console.log("=== Testing Custom baseUrl Configuration ===\n");
    const port = 9999;
    const { server, requestLog } = await createMockProxyServer(port);
    try {
        // Create client with custom baseUrl
        const client = new DeepgramClient({
            apiKey: "test_key_12345",
            baseUrl: `http://localhost:${port}`,
        });
        console.log("Client configured with:");
        console.log(`  baseUrl: http://localhost:${port}`);
        console.log("  (all requests should go to this URL)\n");
        console.log("Running tests...\n");
        // Test 1: Auth endpoint
        console.log("Test 1: Auth endpoint");
        await client.auth.v1.tokens.grant({ scopes: ["usage:write"] });
        // Test 2: Management endpoint
        console.log("Test 2: Management endpoint");
        await client.manage.v1.projects.list();
        // Test 3: Listen endpoint
        console.log("Test 3: Listen endpoint");
        await client.listen.v1.media.transcribeUrl({
            url: "https://example.com/audio.wav",
            model: "nova-3",
        });
        console.log("\n=== Results ===\n");
        console.log("Requests received by proxy:");
        requestLog.forEach((req, i) => {
            console.log(`  ${i + 1}. ${req.method} ${req.path}`);
        });
        console.log("\n=== Verification ===\n");
        // Verify all requests went to the custom baseUrl
        const expectedPaths = ["/v1/auth/grant", "/v1/projects", "/v1/listen"];
        const receivedPaths = requestLog.map((r) => r.path);
        let allCorrect = true;
        expectedPaths.forEach((expected) => {
            if (receivedPaths.includes(expected)) {
                console.log(`✓ ${expected} - Correctly routed to custom baseUrl`);
            }
            else {
                console.log(`✗ ${expected} - NOT found in proxy logs!`);
                allCorrect = false;
            }
        });
        if (allCorrect) {
            console.log("\n✓ All tests passed!");
            console.log("All requests were correctly routed to the custom baseUrl.");
        }
        else {
            console.log("\n✗ Some requests were NOT routed correctly!");
            console.log("This indicates a bug in baseUrl handling.");
            process.exit(1);
        }
    }
    catch (error) {
        console.error("\n✗ Test failed!");
        console.error(`  Error: ${error.message}`);
        if (error.stack) {
            console.error(error.stack);
        }
        process.exit(1);
    }
    finally {
        server.close();
    }
}
// Run test
(async () => {
    await testCustomBaseUrl();
})();
